impl std::fmt::Display for InputEncoding {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::DLogM => write!(f, "dlog-m"),
            Self::ILog => write!(f, "ilog"),
            Self::Srgb => write!(f, "srgb"),
        }
    }
